// Restrict /wp-json/wp/v2/users to authenticated users only
// More reliable than .htaccess for cookie-based authentication detection
add_filter('rest_endpoints', 'vapt_restrict_users_endpoint');
function vapt_restrict_users_endpoint($endpoints) {
    if (isset($endpoints['/wp/v2/users'])) {
        foreach ($endpoints['/wp/v2/users'] as $key => $endpoint) {
            $endpoints['/wp/v2/users'][$key]['permission_callback'] = function() {
                return current_user_can('list_users');
            };
        }
    }
    if (isset($endpoints['/wp/v2/users/(?P<id>[\d]+)'])) {
        foreach ($endpoints['/wp/v2/users/(?P<id>[\d]+)'] as $key => $endpoint) {
            $endpoints['/wp/v2/users/(?P<id>[\d]+)'][$key]['permission_callback'] = function() {
                return current_user_can('list_users');
            };
        }
    }
    return $endpoints;
}

